public int minInsertions(String s) {
    int ans = 0, depth = 0;
    for (int i = 0; i < s.length(); ++i) {
        if (s.charAt(i) == '(') {
            depth += 2;
        } else {
            if (s.charAt(i - 1) == '(') {
                --depth;
            } else {
                depth -= 2;
            }
            if (depth < 0) {
                ans -= depth;
                depth = 0;
            }
        }
    }
    return ans + depth;
}
